create table if not exists public.profiles (id uuid primary key references auth.users(id) on delete cascade,plan text not null default 'free' check(plan in('free','pro')),stripe_customer_id text unique,subscription_status text,updated_at timestamptz not null default now());
create table if not exists public.analyses (id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users(id) on delete cascade,title text not null default 'Resume analysis',overall_score integer not null check(overall_score between 0 and 100),ats_score integer not null check(ats_score between 0 and 100),result jsonb not null,created_at timestamptz not null default now());
alter table public.profiles enable row level security;alter table public.analyses enable row level security;
create policy "profiles_select_own" on public.profiles for select using(auth.uid()=id);create policy "analyses_select_own" on public.analyses for select using(auth.uid()=user_id);create policy "analyses_insert_own" on public.analyses for insert with check(auth.uid()=user_id);create policy "analyses_delete_own" on public.analyses for delete using(auth.uid()=user_id);create index if not exists analyses_user_created_idx on public.analyses(user_id,created_at desc);
